class Solution {
    public String crackSafe(int n, int k) {
        int total = (int) Math.pow(k, n);
        StringBuilder res = new StringBuilder();
        for (int i = 0; i < n; i++) {
            res.append('0');
        }
        boolean[] visited = new boolean[total];
        if (dfs(res, visited, total, k, n)) {
            return res.toString();
        }
        return "";
    }

    private boolean dfs(StringBuilder res, boolean[] visited, int total, int k, int n) {
        if (visited.length == total) {
            return true;
        }
        int prev = getNum(res, n);
        for (int i = 0; i < k; i++) {
            int next = (prev * k + i) % total;
            if (!visited[next]) {
                visited[next] = true;
                res.append(i);
                if (dfs(res, visited, total, k, n)) {
                    return true;
                }
                res.deleteCharAt(res.length() - 1);
                visited[next] = false;
            }
        }
        return false;
    }

    private int getNum(StringBuilder res, int n) {
        int num = 0;
        int len = res.length();
        for (int i = len - n; i < len; i++) {
            num = num * 10 + (res.charAt(i) - '0');
        }
        return num;
    }
}
